record_types.code:
type Entry_Body is record
   Barrier : Barrier_Function_Pointer;
   Action  : Entry_Action_Pointer;
end record;

access_types.code:
type Barrier_Function_Pointer is access
  function
    (O    : System.Address;
     E    : Protected_Entry_Index)
     return Boolean;

type Entry_Action_Pointer is access
  procedure
    (O : System.Address;
     P : System.Address;
     E : Protected_Entry_Index);
